"""Pydantic models and prompts for LLM-generated notebook suggestions."""

from __future__ import annotations

from typing import Any, Literal, Optional

from pydantic import BaseModel, ConfigDict, Field

SuggestionContextType = Literal["local", "global"]


class SuggestedEditModel(BaseModel):
    """Single suggestion generated by the language model."""

    model_config = ConfigDict(extra="forbid")

    id: Optional[str] = None
    title: str
    description: str
    cellIndex: int
    replacementSource: str
    rationale: Optional[str] = None
    contextType: Optional[SuggestionContextType] = None


class SuggestedEditsPayload(BaseModel):
    """Top-level payload returned from the language model."""

    model_config = ConfigDict(extra="forbid")

    suggestions: list[SuggestedEditModel]


class NotebookOutlineItem(BaseModel):
    """Represents an entry in the notebook's logical outline."""
    level: int
    text: str
    cellIndex: int


class NotebookCellSnapshot(BaseModel):
    """Snapshot of a single notebook cell at a point in time."""
    cellType: Literal["code", "markdown", "raw"]
    source: str
    cellIndex: int
    metadata: dict[str, Any] = Field(default_factory=dict)


class ActiveCellContext(BaseModel):
    """Optional state information about the currently active cell's editor."""
    cellIndex: int
    cursorOffset: Optional[int] = None
    selectedText: Optional[str] = None


class NotebookSnapshot(BaseModel):
    """Complete snapshot of a notebook's state and contents."""
    path: str
    activeCellIndex: int
    activeCellContext: Optional[ActiveCellContext] = None
    outline: list[NotebookOutlineItem] = Field(default_factory=list)
    cells: list[NotebookCellSnapshot] = Field(default_factory=list)
    lastActivity: str



__all__ = [
    "SuggestionContextType",
    "SuggestedEditModel",
    "SuggestedEditsPayload",
    "NotebookOutlineItem",
    "NotebookCellSnapshot",
    "ActiveCellContext",
    "NotebookSnapshot",
]
